fetch('/html/_footer.html')
.then(response => { if (!response.ok) { throw new Error('Failed to load footer: ' + response.statusText); } return response.text(); })
.then(data => { const footerPlaceholder = document.getElementById('footer-placeholder'); footerPlaceholder.innerHTML = data; const backToTopBtn = document.createElement('button'); backToTopBtn.id = 'to-top-button'; backToTopBtn.className = 'back-to-top'; backToTopBtn.textContent = '↑'; footerPlaceholder.parentNode.appendChild(backToTopBtn); const footer = document.querySelector('.footer'); if (backToTopBtn && footer) { const checkPosition = () => { if (window.scrollY > 200) { backToTopBtn.style.opacity = '1'; backToTopBtn.style.visibility = 'visible'; } else { backToTopBtn.style.opacity = '0'; backToTopBtn.style.visibility = 'hidden'; } const windowBottom = window.scrollY + window.innerHeight; const footerTop = footer.offsetTop; if (windowBottom > footerTop) { const buttonBottom = windowBottom - footerTop + 20; document.documentElement.style.setProperty('--back-to-top-bottom', `${buttonBottom}px`); } else { document.documentElement.style.setProperty('--back-to-top-bottom', '20px'); } }; window.addEventListener('scroll', checkPosition); window.addEventListener('resize', checkPosition); checkPosition(); backToTopBtn.addEventListener('click', (e) => { e.preventDefault(); window.scrollTo({ top: 0, behavior: 'smooth'
}); }); } })
.catch(error => { console.error('Error fetching footer:', error); document.getElementById('footer-placeholder').innerHTML = '<p>フッターの読み込みに失敗しました。</p>'; });